// English language statistics, frozen reference tables. Used by the cipher
// sieve (text-cipher-sieve.ts) as the natural-English distance metric.
// Standard cryptanalysis tables; the monogram values are Cornell-derived;
// bigram and quadgram values are rough representative log10 frequencies
// (full quadgram dataset is ~389k entries — the embedded subset is just
// the load-bearing top-50). For a production cipher breaker, swap the
// embedded tables for the full Cornell quadgram dataset; the load shape
// stays the same.

/** Normalize a string to A-Z uppercase (drop non-letters). */
export function normalize(text: string): string {
  let out = "";
  for (let i = 0; i < text.length; i++) {
    const c = text.charCodeAt(i);
    // A-Z
    if (c >= 0x41 && c <= 0x5a) {
      out += text.charAt(i);
    } else if (c >= 0x61 && c <= 0x7a) {
      // a-z -> A-Z
      out += String.fromCharCode(c - 0x20);
    }
  }
  return out;
}

// --- Monograms ----------------------------------------------------------

// Cornell English letter frequencies (A..Z).
const MONOGRAM_FREQ: readonly number[] = Object.freeze([
  0.0817, 0.015, 0.0278, 0.0425, 0.127, 0.0223, 0.0202, 0.0609, 0.0697,
  0.0015, 0.0077, 0.0403, 0.0241, 0.0675, 0.0751, 0.0193, 0.001, 0.0599,
  0.0633, 0.0906, 0.0276, 0.0098, 0.0236, 0.0015, 0.0197, 0.0007,
]);

/** log10 monogram probability (length 26 array, A=0, B=1, ..., Z=25). */
export const ENGLISH_MONOGRAM_LOG10: readonly number[] = Object.freeze(
  MONOGRAM_FREQ.map((f) => Math.log10(f)),
);

// --- Bigrams ------------------------------------------------------------

